INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2909c79f-be75-4098-9616-34ec30eefe56',
  '00000000-0000-0000-0000-000000000001',
  $escape$linux_kernel Device Drivers 101: Character vs Block vs Network$escape$,
  $escape$Linux kernel device drivers are categorized into character, block, and network drivers. Character drivers interact with serial ports, terminals, and other character devices. They provide a file interface to access these devices. Block drivers, on the other hand, handle disk I/O operations. They provide a buffer cache and perform disk scheduling. Network drivers manage network interfaces and provide a socket interface to access network resources. To create a kernel module, you need to write a C file that includes the linux/module.h header and exports a module_init function.$escape$,
  $escape$
#include <linux/module.h>
#include <linux/init.h>

MODULE_LICENSE("GPL");
MODULE_AUTHOR("Your Name");
MODULE_DESCRIPTION("A simple kernel module");

static int __init init_module(void)
{
   printk(KERN_INFO "Hello, World!\n");
   return 0;
}

static void __exit exit_module(void)
{
   printk(KERN_INFO "Goodbye, World!\n");
}

module_init(init_module);
module_exit(exit_module);
$escape$,
  $escape$c$escape$,
